    27→	"github.com/prometheus/alertmanager/pkg/labels"
    28→)
    29→
    30→// DefaultRouteOpts are the defaulting routing options which apply
    31→// to the root route of a routing tree.
    32→var DefaultRouteOpts = RouteOpts{
    33→	GroupWait:         30 * time.Second,
    34→	GroupInterval:     5 * time.Minute,
    35→	RepeatInterval:    4 * time.Hour,
    36→	GroupBy:           map[model.LabelName]struct{}{},
    37→	GroupByAll:        false,
    38→	MuteTimeIntervals: []string{},
    39→}
    40→
    41→// A Route is a node that contains definitions of how to handle alerts.
    42→type Route struct {
    43→	parent *Route
    44→
    45→	// The configuration parameters for matches of this route.
    46→	RouteOpts RouteOpts
    47→
    48→	// Matchers an alert has to fulfill to match
    49→	// this route.
    50→	Matchers labels.Matchers
    51→
    52→	// If true, an alert matches further routes on the same level.
    53→	Continue bool
    54→
    55→	// Children routes of this route.
    56→	Routes []*Route
    57→
    58→	// Idx contains the index of this route in the config
    59→	Idx int
    60→}
    61→
    62→// NewRoute returns a new route.
    63→func NewRoute(cr *config.Route, parent *Route) *Route {
    64→	counter := 0
    65→	return newRoute(cr, parent, &counter)
    66→}
    67→
    68→func newRoute(cr *config.Route, parent *Route, counter *int) *Route {
    69→	// Create default and overwrite with configured settings.
    70→	opts := DefaultRouteOpts
    71→	if parent != nil {
    72→		opts = parent.RouteOpts
    73→	}
    74→
    75→	if cr.Receiver != "" {
    76→		opts.Receiver = cr.Receiver
    77→	}
    78→
    79→	if cr.GroupBy != nil {
    80→		opts.GroupBy = map[model.LabelName]struct{}{}
    81→		for _, ln := range cr.GroupBy {
    82→			opts.GroupBy[ln] = struct{}{}
    83→		}
    84→		opts.GroupByAll = false
    85→	} else {
    86→		if cr.GroupByAll {
    87→			opts.GroupByAll = cr.GroupByAll
    88→		}
    89→	}
    90→
    91→	if cr.GroupWait != nil {
    92→		opts.GroupWait = time.Duration(*cr.GroupWait)
    93→	}
    94→	if cr.GroupInterval != nil {
    95→		opts.GroupInterval = time.Duration(*cr.GroupInterval)
    96→	}
    97→	if cr.RepeatInterval != nil {
    98→		opts.RepeatInterval = time.Duration(*cr.RepeatInterval)
    99→	}
   100→
   101→	// Build matchers.
   102→	var matchers labels.Matchers
   103→
   104→	// cr.Match will be deprecated. This for loop appends matchers.
   105→	for ln, lv := range cr.Match {
   106→		matcher, err := labels.NewMatcher(labels.MatchEqual, ln, lv)
   107→		if err != nil {
   108→			// This error must not happen because the config already validates the yaml.
   109→			panic(err)
   110→		}
   111→		matchers = append(matchers, matcher)
   112→	}
   113→
   114→	// cr.MatchRE will be deprecated. This for loop appends regex matchers.
   115→	for ln, lv := range cr.MatchRE {
   116→		matcher, err := labels.NewMatcher(labels.MatchRegexp, ln, lv.String())
   117→		if err != nil {
   118→			// This error must not happen because the config already validates the yaml.
   119→			panic(err)
   120→		}
   121→		matchers = append(matchers, matcher)
   122→	}
   123→
   124→	// We append the new-style matchers. This can be simplified once the deprecated matcher syntax is removed.
   125→	matchers = append(matchers, cr.Matchers...)
   126→
   127→	sort.Sort(matchers)
   128→
   129→	opts.MuteTimeIntervals = cr.MuteTimeIntervals
   130→	opts.ActiveTimeIntervals = cr.ActiveTimeIntervals
   131→
   132→	route := &Route{
   133→		parent:    parent,
   134→		RouteOpts: opts,
   135→		Matchers:  matchers,
   136→		Continue:  cr.Continue,
   137→	}
   138→
   139→	// Create child routes first (they get lower indices)
   140→	route.Routes = newRoutes(cr.Routes, route, counter)
   141→
   142→	// Assign index to this route after all children have been indexed
   143→	route.Idx = *counter
   144→	*counter++
   145→
   146→	return route
   147→}
   148→
   149→// newRoutes returns a slice of routes.
   150→func newRoutes(croutes []*config.Route, parent *Route, counter *int) []*Route {
   151→	res := []*Route{}
   152→	for _, cr := range croutes {
   153→		res = append(res, newRoute(cr, parent, counter))
   154→	}
   155→	return res
   156→}
   157→
   158→// Match does a depth-first left-to-right search through the route tree
   159→// and returns the matching routing nodes.
   160→func (r *Route) Match(lset model.LabelSet) []*Route {
   161→	if !r.Matchers.Matches(lset) {
   162→		return nil
   163→	}
   164→
   165→	var all []*Route
   166→
   167→	for _, cr := range r.Routes {
   168→		matches := cr.Match(lset)
   169→
   170→		all = append(all, matches...)
   171→
   172→		if matches != nil && !cr.Continue {
   173→			break
   174→		}
   175→	}
   176→
   177→	// If no child nodes were matches, the current node itself is a match.
   178→	if len(all) == 0 {
   179→		all = append(all, r)
   180→	}
   181→
   182→	return all
   183→}
   184→
   185→// Key returns a key for the route. It does not uniquely identify the route in general.
   186→func (r *Route) Key() string {
   187→	b := strings.Builder{}
   188→
   189→	if r.parent != nil {
   190→		b.WriteString(r.parent.Key())
   191→		b.WriteRune('/')
   192→	}
   193→	b.WriteString(r.Matchers.String())
   194→	return b.String()
   195→}
   196→
   197→// ID returns a unique identifier for the route.
   198→func (r *Route) ID() string {
   199→	b := strings.Builder{}
   200→
   201→	if r.parent != nil {
   202→		b.WriteString(r.parent.ID())
   203→		b.WriteRune('/')
   204→	}
   205→
   206→	b.WriteString(r.Matchers.String())
   207→
   208→	if r.parent != nil {
   209→		for i := range r.parent.Routes {
   210→			if r == r.parent.Routes[i] {
   211→				b.WriteRune('/')
   212→				b.WriteString(strconv.Itoa(i))
   213→				break
   214→			}
   215→		}
   216→	}
   217→
   218→	return b.String()
   219→}
   220→
   221→// Walk traverses the route tree in depth-first order.
   222→func (r *Route) Walk(visit func(*Route)) {
   223→	visit(r)
   224→	for i := range r.Routes {
   225→		r.Routes[i].Walk(visit)
   226→	}
   227→}
   228→
   229→// RouteOpts holds various routing options necessary for processing alerts
   230→// that match a given route.
   231→type RouteOpts struct {
   232→	// The identifier of the associated notification configuration.
   233→	Receiver string
   234→
   235→	// What labels to group alerts by for notifications.
   236→	GroupBy map[model.LabelName]struct{}
   237→
   238→	// Use all alert labels to group.
   239→	GroupByAll bool
   240→
   241→	// How long to wait to group matching alerts before sending
   242→	// a notification.
   243→	GroupWait      time.Duration
   244→	GroupInterval  time.Duration
   245→	RepeatInterval time.Duration
   246→
   247→	// A list of time intervals for which the route is muted.
   248→	MuteTimeIntervals []string
   249→
   250→	// A list of time intervals for which the route is active.
   251→	ActiveTimeIntervals []string
   252→}
   253→
   254→func (ro *RouteOpts) String() string {
